mapper.select:

SELECT s.store_id id , s.store_name name, s.min_price min, s.rating_avg avg, s.rating_sum sum, s.order_sum count, s.store_pic pic
FROM store s join store_category c on s.store_id=c.store_id


        AND s.store_name LIKE CONCAT('%', #{searchText}, '%')


        AND c.category_id = #{categoryId}


ORDER BY s.order_sum DESC
LIMIT #{startIdx}, #{size}
